function minIndex(a, i) {
  let m = i;
  for (let j = i + 1; j < a.length; j++) {
    if (a[j] < a[m]) m = j;
  }
  return m;
}

function selectionSort(a) {
  for (let i = 0; i < a.length; i++) {
    let m = i;
    for (let j = i + 1; j < a.length; j++) {
      if (a[j] < a[m]) m = j;
    }
    const t = a[i];
    a[i] = a[m];
    a[m] = t;
  }
  return a;
}

function insertionSort(a) {
  for (let i = 1; i < a.length; i++) {
    const key = a[i];
    let j = i - 1;
    while (j >= 0 && a[j] > key) {
      a[j + 1] = a[j];
      j--;
    }
    a[j + 1] = key;
  }
  return a;
}

