function merge(L, R) {
  const res = [];
  let i = 0, j = 0;
  while (i < L.length && j < R.length) {
    if (L[i] <= R[j]) { res.push(L[i]); i++; }
    else { res.push(R[j]); j++; }
  }
  while (i < L.length) { res.push(L[i]); i++; }
  while (j < R.length) { res.push(R[j]); j++; }
  return res;
}

