function quickSort(a) {
  function partition(lo, hi) {
    const pivot = a[hi];
    let i = lo;
    for (let j = lo; j < hi; j++) {
      if (a[j] < pivot) {
        const t = a[i];
        a[i] = a[j];
        a[j] = t;
        i++;
      }
    }
    const t = a[i];
    a[i] = a[hi];
    a[hi] = t;
    return i;
  }
  function qs(lo, hi) {
    if (lo >= hi) return;
    const p = partition(lo, hi);
    qs(lo, p - 1);
    qs(p + 1, hi);
  }
  qs(0, a.length - 1);
  return a;
}

