function twoSumSorted(a, target) {
  const b = a.slice().sort((x, y) => x - y);
  let i = 0, j = b.length - 1;
  while (i < j) {
    const s = b[i] + b[j];
    if (s === target) return [b[i], b[j]];
    else if (s < target) i++;
    else j--;
  }
  return null;
}

function byLength(words) {
  return words.slice().sort((a, b) => a.length - b.length);
}

